#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int* P = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &P[i]);
        }
        int** pairs = (int**)malloc(M * sizeof(int*));
        for (int i = 0; i < M; i++) {
            pairs[i] = (int*)malloc(2 * sizeof(int));
            scanf("%d %d", &pairs[i][0], &pairs[i][1]);
        }
        // Check if permutation P can be obtained
        int* visited = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            visited[i] = 0;
        }
        for (int i = 0; i < M; i++) {
            for (int j = pairs[i][0] - 1; j < pairs[i][1]; j++) {
                visited[j] = 1;
            }
        }
        int possible = 1;
        for (int i = 0; i < N; i++) {
            if (!visited[i]) {
                possible = 0;
                break;
            }
        }
        if (possible) {
            printf("Possible\n");
        } else {
            printf("Impossible\n");
        }
        free(P);
        for (int i = 0; i < M; i++) {
            free(pairs[i]);
        }
        free(pairs);
        free(visited);
    }
    return 0;
}

